    /// <summary>
    /// Extract author from <meta name='author'> tag
    /// </summary>
    [Fact]
    public void TestMetadataAuthorMeta()
    {
        var html = "<html><head><title>Page</title><meta name=\"author\" content=\"Jane Doe\"></head><body><p>Content</p></body></html>";
        var result = HtmlToMarkdownConverter.Convert(html, "{\"extractMetadata\":true}");
        var content = result.Content ?? "";

        Assert.False(string.IsNullOrWhiteSpace(content));
    }

