    /// <summary>
    /// JSON-LD script tag is stripped from output (security) but metadata may be extracted
    /// </summary>
    [Fact]
    public void TestStructuredDataJsonLd()
    {
        var html = "<html><head><title>Article</title><script type=\"application/ld+json\">{\"@context\":\"https://schema.org\",\"@type\":\"Article\",\"headline\":\"My Article\",\"author\":{\"@type\":\"Person\",\"name\":\"Jane Doe\"},\"datePublished\":\"2024-01-15\"}</script></head><body><h1>My Article</h1><p>Article body text.</p></body></html>";
        var result = HtmlToMarkdownConverter.Convert(html, "{\"extractMetadata\":true}");
        var content = result.Content ?? "";

        Assert.False(string.IsNullOrWhiteSpace(content));
        Assert.Contains("My Article", content);
        Assert.DoesNotContain("application/ld+json", content);
        Assert.DoesNotContain("@context", content);
        Assert.DoesNotContain("schema.org", content);
    }

    /// <summary>
    /// Multiple JSON-LD blocks are all stripped from output
    /// </summary>
    [Fact]
    public void TestStructuredDataMultipleJsonLd()
    {
        var html = "<html><head><title>Shop Page</title><script type=\"application/ld+json\">{\"@context\":\"https://schema.org\",\"@type\":\"Product\",\"name\":\"Widget\",\"price\":\"9.99\"}</script><script type=\"application/ld+json\">{\"@context\":\"https://schema.org\",\"@type\":\"BreadcrumbList\",\"itemListElement\":[{\"@type\":\"ListItem\",\"position\":1,\"name\":\"Home\"}]}</script></head><body><h1>Widget</h1><p>A great widget for all purposes.</p></body></html>";
        var result = HtmlToMarkdownConverter.Convert(html, "{\"extractMetadata\":true}");
        var content = result.Content ?? "";

        Assert.False(string.IsNullOrWhiteSpace(content));
        Assert.Contains("Widget", content);
        Assert.DoesNotContain("@context", content);
        Assert.DoesNotContain("BreadcrumbList", content);
        Assert.DoesNotContain("ListItem", content);
    }

